SELECT *
FROM todos
WHERE todo_id  = #{todoId}
  AND user_id  = #{userId}
  AND is_deleted = 0

SELECT *
FROM todos
WHERE user_id    = #{userId}
  AND is_deleted = 0
  AND todo_date  = #{todoDate}

      AND status = #{status}

ORDER BY
    FIELD(priority, 'HIGH', 'MEDIUM', 'LOW'),
    todo_id ASC

SELECT COUNT(*)
FROM todos
WHERE user_id    = #{userId}
  AND is_deleted = 0
  AND todo_date  = #{todoDate}

SELECT COUNT(*)
FROM todos
WHERE user_id    = #{userId}
  AND is_deleted = 0
  AND todo_date  = #{todoDate}
  AND status     = 'DONE'
